+/// Convert profile KV cache type to GGML type constant
+pub fn profileKVTypeToGGML(kv_type: anytype) c_uint {
+    // Import profile module to get KVCacheType enum
+    const KVCacheType = @import("profile.zig").KVCacheType;
+
+    return switch (@as(KVCacheType, kv_type)) {
+        .fp16 => c.GGML_TYPE_F16,
+        .q8_0 => c.GGML_TYPE_Q8_0,
+        .q4_0 => c.GGML_TYPE_Q4_0,
+    };
+}
+
+/// Load model with optimization profile
+pub fn loadWithProfile(profile: anytype) !Model {
+    const opts = ModelOptions{
+        .n_gpu_layers = profile.optimal_config.n_gpu_layers,
+        .use_mmap = true,
+        .use_mlock = false,
+        .vocab_only = false,
+    };
+
+    return try Model.load(profile.model_path, opts);
+}
+
+/// Initialize context with optimization profile
+pub fn initContextWithProfile(model: *const Model, profile: anytype) !Context {
+    const kv_type = profileKVTypeToGGML(profile.optimal_config.kv_type);
+
+    const opts = ContextOptions{
+        .n_ctx = profile.optimal_config.n_ctx,
+        .n_batch = profile.optimal_config.n_batch,
+        .n_threads = profile.optimal_config.n_threads,
+        .kv_type = kv_type,
+    };
+
+    return try Context.init(model, opts);
+}

