+const std = @import("std");
+
+/// Compute SHA256 hash of model file (first 1MB for speed)
+/// Returns hex-encoded hash string
+pub fn computeModelHash(allocator: std.mem.Allocator, model_path: []const u8) ![]u8 {
+    const file = try std.fs.cwd().openFile(model_path, .{});
+    defer file.close();
+
+    // Read first 1MB for hashing (sufficient for uniqueness, faster than full file)
+    const read_size = 1024 * 1024; // 1 MB
+    var buffer: [read_size]u8 = undefined;
+    const bytes_read = try file.readAll(&buffer);
+
+    // Compute SHA256
+    var hasher = std.crypto.hash.sha2.Sha256.init(.{});
+    hasher.update(buffer[0..bytes_read]);
+    var hash_bytes: [32]u8 = undefined;
+    hasher.final(&hash_bytes);
+
+    // Convert to hex string
+    const hex_hash = try allocator.alloc(u8, 64); // 32 bytes = 64 hex chars
+    const hex_array = std.fmt.bytesToHex(&hash_bytes, .lower);
+    const formatted = try std.fmt.bufPrint(hex_hash, "{s}", .{&hex_array});
+
+    // Return only the formatted part
+    return try allocator.dupe(u8, formatted);
+}
+
+/// Get profile file path for a model
+pub fn getProfilePath(allocator: std.mem.Allocator, model_path: []const u8) ![]u8 {
+    const hash = try computeModelHash(allocator, model_path);
+    defer allocator.free(hash);
+
+    const home = std.posix.getenv("HOME") orelse return error.NoHomeDir;
+
+    // Ensure cache directory exists
+    const cache_dir = try std.fmt.allocPrint(allocator, "{s}/.cache/zell/profiles", .{home});
+    defer allocator.free(cache_dir);
+
+    std.fs.cwd().makePath(cache_dir) catch |err| {
+        if (err != error.PathAlreadyExists) return err;
+    };
+
+    // Return full profile path
+    return try std.fmt.allocPrint(
+        allocator,
+        "{s}/.cache/zell/profiles/{s}.json",
+        .{ home, hash },
+    );
+}
+
+/// Get shader cache path for a model
+pub fn getShaderPath(allocator: std.mem.Allocator, model_path: []const u8) ![]u8 {
+    const hash = try computeModelHash(allocator, model_path);
+    defer allocator.free(hash);
+
+    const home = std.posix.getenv("HOME") orelse return error.NoHomeDir;
+
+    // Ensure cache directory exists
+    const cache_dir = try std.fmt.allocPrint(allocator, "{s}/.cache/zell/shaders", .{home});
+    defer allocator.free(cache_dir);
+
+    std.fs.cwd().makePath(cache_dir) catch |err| {
+        if (err != error.PathAlreadyExists) return err;
+    };
+
+    // Return full shader path
+    return try std.fmt.allocPrint(
+        allocator,
+        "{s}/.cache/zell/shaders/{s}.metallib",
+        .{ home, hash },
+    );
+}
+
+/// Check if profile exists for a model
+pub fn profileExists(allocator: std.mem.Allocator, model_path: []const u8) bool {
+    const profile_path = getProfilePath(allocator, model_path) catch return false;
+    defer allocator.free(profile_path);
+
+    std.fs.cwd().access(profile_path, .{}) catch return false;
+    return true;
+}
+
+/// Delete profile for a model
+pub fn deleteProfile(allocator: std.mem.Allocator, model_path: []const u8) !void {
+    const profile_path = try getProfilePath(allocator, model_path);
+    defer allocator.free(profile_path);
+
+    try std.fs.cwd().deleteFile(profile_path);
+}
+
+/// Delete shader cache for a model
+pub fn deleteShaderCache(allocator: std.mem.Allocator, model_path: []const u8) !void {
+    const shader_path = try getShaderPath(allocator, model_path);
+    defer allocator.free(shader_path);
+
+    try std.fs.cwd().deleteFile(shader_path);
+}
+
+/// Clear all profiles and shader caches
+pub fn clearAllCaches(allocator: std.mem.Allocator) !void {
+    const home = std.posix.getenv("HOME") orelse return error.NoHomeDir;
+
+    // Clear profiles
+    const profile_dir = try std.fmt.allocPrint(allocator, "{s}/.cache/zell/profiles", .{home});
+    defer allocator.free(profile_dir);
+
+    std.fs.cwd().deleteTree(profile_dir) catch |err| {
+        if (err != error.FileNotFound) return err;
+    };
+
+    // Clear shaders
+    const shader_dir = try std.fmt.allocPrint(allocator, "{s}/.cache/zell/shaders", .{home});
+    defer allocator.free(shader_dir);
+
+    std.fs.cwd().deleteTree(shader_dir) catch |err| {
+        if (err != error.FileNotFound) return err;
+    };
+}

