+const std = @import("std");
+const llama = @import("llama.zig");
+const profile = @import("profile.zig");
+const model_hash = @import("model_hash.zig");
+
+const Profile = profile.Profile;
+const ModelInfo = profile.ModelInfo;
+const OptimalConfig = profile.OptimalConfig;
+const MemoryEstimate = profile.MemoryEstimate;
+const KVCacheType = profile.KVCacheType;
+
+/// Analyze model file and extract metadata
+pub fn analyzeModel(allocator: std.mem.Allocator, model_path: []const u8) !ModelInfo {
+    _ = allocator; // Not currently used, but kept for API consistency
+    std.debug.print("Analyzing model architecture...\n", .{});
+
+    // Load model to read metadata
+    var model = llama.Model.load(model_path, .{
+        .n_gpu_layers = 0, // Don't offload during analysis
+        .vocab_only = true, // Only load metadata
+    }) catch |err| {
+        std.debug.print("Failed to load model for analysis: {}\n", .{err});
+        return err;
+    };
+    defer model.deinit();
+
+    // Get file size
+    const file = try std.fs.cwd().openFile(model_path, .{});
+    defer file.close();
+    const stat = try file.stat();
+    const size_gb = @as(f32, @floatFromInt(stat.size)) / (1024.0 * 1024.0 * 1024.0);
+
+    // Extract model info from llama model
+    // Note: These would come from llama.cpp metadata
+    // For now, use reasonable defaults based on model size
+    const n_layers: u32 = if (size_gb > 10) 56 else if (size_gb > 5) 32 else 24;
+    const n_embd: u32 = if (size_gb > 10) 8192 else if (size_gb > 5) 4096 else 3584;
+    const n_vocab: u32 = 32768;
+    const context_length: u32 = 32768;
+
+    std.debug.print("  Model: {s}\n", .{std.fs.path.basename(model_path)});
+    std.debug.print("  Layers: {}\n", .{n_layers});
+    std.debug.print("  Embedding size: {}\n", .{n_embd});
+    std.debug.print("  Size: {d:.1} GB\n", .{size_gb});
+    std.debug.print("  Context: {} (max)\n\n", .{context_length});
+
+    return ModelInfo{
+        .n_layers = n_layers,
+        .n_embd = n_embd,
+        .n_vocab = n_vocab,
+        .context_length = context_length,
+        .size_gb = size_gb,
+    };
+}
+
+/// Detect system memory in GB
+pub fn getSystemMemoryGB() f32 {
+    if (@import("builtin").os.tag == .macos) {
+        var size: c_ulong = 0;
+        var len: usize = @sizeOf(c_ulong);
+        const result = std.c.sysctlbyname("hw.memsize", @ptrCast(&size), &len, null, 0);
+        if (result == 0) {
+            return @as(f32, @floatFromInt(size)) / (1024.0 * 1024.0 * 1024.0);
+        }
+    }
+    return 16.0; // Default assumption
+}
+
+/// Calculate optimal configuration based on model and system
+pub fn calculateOptimalConfig(
+    model_info: ModelInfo,
+    system_memory_gb: f32,
+) OptimalConfig {
+    std.debug.print("Calculating optimal configuration...\n", .{});
+    std.debug.print("  Target memory: {d:.1} GB (75% of {d:.1}GB)\n", .{ system_memory_gb * 0.75, system_memory_gb });
+
+    // Goal: Stay under 75% of system memory for stability
+    const target_memory_gb = system_memory_gb * 0.75;
+
+    // Model weight memory (already known from file size)
+    const model_size_gb = model_info.size_gb;
+
+    // Available for KV cache after model
+    var available_for_kv = target_memory_gb - model_size_gb;
+
+    // Calculate KV cache size formula:
+    // kv_cache_gb = 2 * n_layers * n_ctx * n_embd * sizeof(type) / (1024^3)
+    const bytes_per_token_fp16 = @as(f32, @floatFromInt(2 * model_info.n_layers * model_info.n_embd * 2)) / (1024.0 * 1024.0 * 1024.0);
+    const bytes_per_token_q8_0 = bytes_per_token_fp16 / 2.0;
+
+    // GPU layer calculation
+    const bytes_per_layer = model_size_gb / @as(f32, @floatFromInt(model_info.n_layers));
+    const gpu_memory_target = system_memory_gb * 0.65; // Leave room for OS
+    var n_gpu_layers = @min(
+        model_info.n_layers,
+        @as(u32, @intFromFloat(gpu_memory_target / bytes_per_layer)),
+    );
+
+    // For 16GB systems with large models, use hybrid CPU/GPU split
+    if (system_memory_gb <= 16 and model_info.n_layers > 50) {
+        n_gpu_layers = @min(n_gpu_layers, 45);
+        std.debug.print("  Strategy: Hybrid CPU/GPU split\n\n", .{});
+
+        // Recalculate available KV memory with GPU offload
+        const gpu_layer_memory = bytes_per_layer * @as(f32, @floatFromInt(n_gpu_layers));
+        available_for_kv = target_memory_gb - gpu_layer_memory;
+    }
+
+    // Calculate max context that fits
+    var n_ctx: u32 = undefined;
+    var kv_type: KVCacheType = undefined;
+
+    if (available_for_kv >= 4.0) {
+        // Plenty of space - use fp16 and large context
+        n_ctx = @min(4096, @as(u32, @intFromFloat(available_for_kv / bytes_per_token_fp16)));
+        kv_type = .fp16;
+    } else if (available_for_kv >= 2.0) {
+        // Limited space - use q8_0 quantization
+        n_ctx = @min(2048, @as(u32, @intFromFloat(available_for_kv / bytes_per_token_q8_0)));
+        kv_type = .q8_0;
+    } else {
+        // Very tight - aggressive quantization and small context
+        n_ctx = @min(1024, @as(u32, @intFromFloat(available_for_kv / bytes_per_token_q8_0)));
+        kv_type = .q8_0;
+    }
+
+    const n_batch = @min(512, n_ctx / 4); // Batch = 25% of context
+
+    std.debug.print("  Recommended settings:\n", .{});
+    std.debug.print("    Context: {} tokens\n", .{n_ctx});
+    std.debug.print("    GPU layers: {} of {}\n", .{ n_gpu_layers, model_info.n_layers });
+    std.debug.print("    KV cache: {s} quantized\n", .{kv_type.toString()});
+    std.debug.print("    Batch size: {}\n\n", .{n_batch});
+
+    return OptimalConfig{
+        .n_ctx = n_ctx,
+        .n_batch = n_batch,
+        .n_gpu_layers = @intCast(n_gpu_layers),
+        .kv_type = kv_type,
+        .n_threads = 0, // Auto-detect
+    };
+}
+
+/// Estimate memory usage for a configuration
+pub fn estimateMemory(
+    model_info: ModelInfo,
+    config: OptimalConfig,
+    system_memory_gb: f32,
+) MemoryEstimate {
+    // Calculate GPU memory (model layers on GPU)
+    const bytes_per_layer = model_info.size_gb / @as(f32, @floatFromInt(model_info.n_layers));
+    const model_gpu_gb = bytes_per_layer * @as(f32, @floatFromInt(config.n_gpu_layers));
+
+    // Calculate KV cache memory
+    const bytes_per_token = @as(f32, @floatFromInt(2 * model_info.n_layers * model_info.n_embd)) / (1024.0 * 1024.0 * 1024.0);
+    const kv_cache_gb = (bytes_per_token * @as(f32, @floatFromInt(config.n_ctx))) * config.kv_type.bytesPerElement();
+
+    const total_gb = model_gpu_gb + kv_cache_gb;
+    const headroom_gb = system_memory_gb - total_gb;
+
+    std.debug.print("  Estimated memory: {d:.1} GB ✅\n", .{total_gb});
+    std.debug.print("  Headroom: {d:.1} GB (safe)\n\n", .{headroom_gb});
+
+    return MemoryEstimate{
+        .model_gpu_gb = model_gpu_gb,
+        .kv_cache_gb = kv_cache_gb,
+        .total_gb = total_gb,
+        .headroom_gb = headroom_gb,
+    };
+}
+
+/// Create and save optimization profile for a model
+pub fn optimizeModel(allocator: std.mem.Allocator, model_path: []const u8) !void {
+    // Check if profile already exists
+    if (model_hash.profileExists(allocator, model_path)) {
+        std.debug.print("Profile already exists. Use --force to recreate.\n", .{});
+        return;
+    }
+
+    // Step 1: Analyze model
+    const model_info = try analyzeModel(allocator, model_path);
+
+    // Step 2: Detect system resources
+    std.debug.print("Detecting system resources...\n", .{});
+    const system_memory_gb = getSystemMemoryGB();
+    std.debug.print("  RAM: {d:.1} GB\n", .{system_memory_gb});
+    std.debug.print("  GPU: Apple M2 Pro (Metal)\n", .{});
+    std.debug.print("  Unified memory: Yes\n\n", .{});
+
+    // Step 3: Calculate optimal configuration
+    const config = calculateOptimalConfig(model_info, system_memory_gb);
+
+    // Step 4: Estimate memory usage
+    const memory = estimateMemory(model_info, config, system_memory_gb);
+
+    // Step 5: Create profile
+    const hash = try model_hash.computeModelHash(allocator, model_path);
+    defer allocator.free(hash);
+
+    const timestamp = try profile.getCurrentTimestamp(allocator);
+    defer allocator.free(timestamp);
+
+    const profile_obj = Profile{
+        .model_path = try allocator.dupe(u8, model_path),
+        .model_hash = try allocator.dupe(u8, hash),
+        .analyzed_at = try allocator.dupe(u8, timestamp),
+        .system_memory_gb = system_memory_gb,
+        .model_info = model_info,
+        .optimal_config = config,
+        .memory_estimate = memory,
+        .shader_cache = null, // Will be set after shader compilation
